// ==========================================
// Get random items from a category
// ==========================================
export function getRandomContent(category, count = 1) {
    const pool = contentDB[category];
    if (!pool) return [];
    const shuffled = [...pool].sort(() => Math.random() - 0.5);
    return shuffled.slice(0, Math.min(count, shuffled.length));
}

export function getRandomGradient() {
    return gradients[Math.floor(Math.random() * gradients.length)];
}

export function getRandomAccent() {
    return accentColors[Math.floor(Math.random() * accentColors.length)];
}

/**
 * Auto-generate a complete Short config — zero input needed
 */
export function autoGenerateShort() {
    const categories = ['motivation', 'facts', 'tips', 'trending', 'poems', 'animation'];
    const category = categories[Math.floor(Math.random() * categories.length)];
    const [content] = getRandomContent(category, 1);
    const gradient = getRandomGradient();
    const accent = getRandomAccent();
    const textColor = '#ffffff';

    const templateMap = { motivation: 'quotes', facts: 'facts', tips: 'tips', trending: 'trending', poems: 'poems', animation: 'animation' };
    const durationMap = { motivation: 7, facts: 9, tips: 8, trending: 8, poems: 10, animation: 8 };

    return {
        category,
        content,
        style: { gradient, textColor, accentColor: accent },
        duration: durationMap[category] || 8,
        templateId: templateMap[category] || 'quotes'
    };
}

/**
 * Auto-generate a batch of unique Shorts
 */
export function autoGenerateBatch(count = 5) {
    const shorts = [];
    const usedTexts = new Set();

    for (let i = 0; i < count; i++) {
        let short;
        let attempts = 0;
        do {
            short = autoGenerateShort();
            attempts++;
        } while (usedTexts.has(short.content.text) && attempts < 20);
        usedTexts.add(short.content.text);
        shorts.push({ ...short, id: Date.now() + i });
    }
    return shorts;
}
